// Format the image check API response as a readable message
const data = $input.first().json;

const emoji = data.emoji || '🔍';
const label = data.label || data.verdict;
const confidence = Math.round((data.confidence || 0) * 100);
const description = data.description || 'No description available.';
const explanation = data.explanation || 'No explanation available.';
const tip = data.educational_tip || '';
const sources = data.sources || [];
const aiSignals = data.ai_generation_signals || [];
const manipSignals = data.manipulation_signals || [];
const contextAnalysis = data.context_analysis || '';
const evidence = data.evidence_summary || {};
const responseTime = data.response_time_seconds || 0;

let message = `${emoji} **${label}** (${confidence}% confidence)\n\n`;
message += `**Image:** ${description}\n\n`;
message += `${explanation}\n\n`;

// AI generation signals
if (aiSignals.length > 0) {
  message += `🤖 **AI Generation Signals:**\n`;
  for (const signal of aiSignals) {
    message += `• ${signal}\n`;
  }
  message += `\n`;
}

// Manipulation signals
if (manipSignals.length > 0) {
  message += `🖌️ **Manipulation Signals:**\n`;
  for (const signal of manipSignals) {
    message += `• ${signal}\n`;
  }
  message += `\n`;
}

// Context analysis
if (contextAnalysis) {
  message += `🔄 **Context Analysis:** ${contextAnalysis}\n\n`;
}

// Sources section
if (sources.length > 0) {
  message += `📋 **Sources:**\n`;
  for (const source of sources) {
    message += `• **${source.name}** — ${source.snippet}`;
    if (source.url) {
      message += ` ([link](${source.url}))`;
    }
    message += `\n`;
  }
  message += `\n`;
}

// Educational tip
if (tip) {
  message += `💡 **Tip:** ${tip}\n\n`;
}

// Evidence summary
message += `---\n`;
message += `_Checked ${evidence.reverse_search_results || 0} reverse image sources `;
message += `in ${responseTime}s_`;

return [{ json: { output: message } }];
